const spendData = $('Execute a SQL query').all();
const leadsData = $('Execute a SQL query1').all();

let tableRows = '';

const results = spendData.map(spend => {
  const s = spend.json;
  const lead = leadsData.find(l => l.json.campaign_id === s.campaign_id)?.json || {};

  const totalSpent = parseFloat(s.total_spent) || 0;
  const totalConversions = parseInt(s.total_conversions) || 0;
  const totalClicks = parseInt(s.total_clicks) || 0;
  const totalRevenue = parseFloat(lead.total_revenue) || 0;
  const totalLeads = parseInt(lead.total_leads) || 0;
  const avgQuality = parseFloat(lead.avg_lead_quality) || 0;

  const CAC = totalConversions > 0 ? (totalSpent / totalConversions).toFixed(2) : 0;
  const ROI = totalSpent > 0 ? (((totalRevenue - totalSpent) / totalSpent) * 100).toFixed(2) : 0;
  const conversionRate = totalClicks > 0 ? ((totalConversions / totalClicks) * 100).toFixed(2) : 0;

  tableRows += `
    <tr>
      <td>${s.campaign_name}</td>
      <td>${s.channel}</td>
      <td>${s.status}</td>
      <td>$${s.budget_allocated}</td>
      <td>$${totalSpent}</td>
      <td>$${totalRevenue}</td>
      <td>${totalLeads}</td>
      <td>$${CAC}</td>
      <td>${ROI}%</td>
      <td>${conversionRate}%</td>
    </tr>`;

  return {
    json: {
      campaign_name: s.campaign_name,
      channel: s.channel,
      status: s.status,
      budget_allocated: s.budget_allocated,
      total_spent: totalSpent,
      total_revenue: totalRevenue,
      total_leads: totalLeads,
      avg_lead_quality: avgQuality.toFixed(2),
      CAC: CAC,
      ROI: `${ROI}%`,
      conversion_rate: `${conversionRate}%`
    }
  };
});

const emailHTML = `
<h2 style="color:#003087">TDK Marketing Intelligence Report</h2>
<p>Generated: ${new Date().toISOString().split('T')[0]}</p>
<table border="1" cellpadding="8" style="border-collapse:collapse; width:100%">
  <tr style="background:#003087; color:white;">
    <th>Campaign</th>
    <th>Channel</th>
    <th>Status</th>
    <th>Budget</th>
    <th>Spent</th>
    <th>Revenue</th>
    <th>Leads</th>
    <th>CAC</th>
    <th>ROI</th>
    <th>Conv. Rate</th>
  </tr>
  ${tableRows}
</table>
<br>
<p style="color:gray; font-size:12px">Auto-generated by TDK Marketing Intelligence Workflow | n8n</p>
`;

results[0].json.emailHTML = emailHTML;

return results;
